function setupCanvas(){var r=cc.getBoundingClientRect();dpr=window.devicePixelRatio||1;W=Math.max(100,Math.round(r.width-16));H=Math.max(100,Math.round(r.height-16));cv.width=W*dpr;cv.height=H*dpr;cv.style.width=W+'px';cv.style.height=H+'px';cx.setTransform(dpr,0,0,dpr,0,0);Engine.reqRender();}
