function pRectLandscape(){var pad=20,ratios={futsal:2,football:105/68,beach:36/27,mini:50/30,basketball:28/15,volleyball:18/9,handball:40/20},ar=ratios[sport]||2;var w=Math.max(100,W-2*pad),h=w/ar;if(h>H-2*pad){h=Math.max(100,H-2*pad);w=h*ar;}var px=(W-w)/2,py=(H-h)/2;return{x:px,y:py,w:Math.max(10,w),h:Math.max(10,h),fw:Math.max(10,w),fh:Math.max(10,h)};}
