function initBottomPanelResize(){var handle=document.getElementById('bpResizeHandle');var panel=document.getElementById('bottomPanel');if(!handle||!panel)return;var startY,startH;handle.addEventListener('mousedown',function(e){e.preventDefault();startY=e.clientY;startH=panel.offsetHeight;document.addEventListener('mousemove',onDrag);document.addEventListener('mouseup',onUp);});function onDrag(e){var newH=startH+(startY-e.clientY);newH=Math.max(40,Math.min(300,newH));panel.style.height=newH+'px';var scenes=panel.querySelector('.bp-scenes');if(scenes)scenes.style.display=newH>80?'flex':'none';setupCanvas();}function onUp(){document.removeEventListener('mousemove',onDrag);document.removeEventListener('mouseup',onUp);}}
