function duplicateSel(){var ne=[];selIds.forEach(function(id){var el=els.find(function(e){return e.id===id;});if(el){var cp=JSON.parse(JSON.stringify(el));cp.id=uid();cp.x+=20;cp.y+=20;if(cp.points)cp.points=cp.points.map(function(p){return{x:p.x+20,y:p.y+20};});if(cp.ax2!==undefined){cp.ax2+=20;cp.ay2+=20;}cp.linkedToId=null;ne.push(cp);}});ne.forEach(function(e){els.push(e);});selIds.clear();ne.forEach(function(e){selIds.add(e.id);});saveH();updateProps();updateLayers();Engine.reqRender();toast(t('copied'));}
