function setCtxColor(c){selIds.forEach(function(id){var el=els.find(function(e){return e.id===id;});if(el)el.color=c;});saveH();updateProps();Engine.reqRender();}
function setCtxSize(v){selIds.forEach(function(id){var el=els.find(function(e){return e.id===id;});if(el)el.size=v;});saveH();updateProps();Engine.reqRender();}
function setCtxOpacity(v){selIds.forEach(function(id){var el=els.find(function(e){return e.id===id;});if(el)el.opacity=v;});saveH();updateProps();Engine.reqRender();}
function rotateSel90(){selIds.forEach(function(id){var el=els.find(function(e){return e.id===id;});if(el)el.rotation=((el.rotation||0)+90)%360;});saveH();updateProps();Engine.reqRender();}
function flipSelH(){selIds.forEach(function(id){var el=els.find(function(e){return e.id===id;});if(el){el.flipH=!el.flipH;if(el.ax2!==undefined){el.ax2=el.x+(el.x-el.ax2);}}});saveH();updateProps();Engine.reqRender();}
function flipSelV(){selIds.forEach(function(id){var el=els.find(function(e){return e.id===id;});if(el){el.flipV=!el.flipV;if(el.ay2!==undefined){el.ay2=el.y+(el.y-el.ay2);}}});saveH();updateProps();Engine.reqRender();}
function toggleVisSel(){selIds.forEach(function(id){var el=els.find(function(e){return e.id===id;});if(el)el.hidden=!el.hidden;});updateProps();updateLayers();Engine.reqRender();}
function editSelText(){if(selIds.size!==1)return;var id=Array.from(selIds)[0];var el=els.find(function(e){return e.id===id;});if(!el||el.type!=='text')return;var txt=prompt(lang==='ar'?'أدخل النص:':'Enter text:',el.text||'');if(txt!==null){el.text=txt;saveH();updateProps();Engine.reqRender();}}
function copyCtxStyle(){if(!_ctxSelectedEl)return;_ctxStyleClipboard={color:_ctxSelectedEl.color,size:_ctxSelectedEl.size,opacity:_ctxSelectedEl.opacity,rotation:_ctxSelectedEl.rotation};toast(lang==='ar'?'تم نسخ النمط':'Style copied');}
function pasteCtxStyle(){if(!_ctxStyleClipboard||!selIds.size)return;selIds.forEach(function(id){var el=els.find(function(e){return e.id===id;});if(el){if(_ctxStyleClipboard.color!==undefined)el.color=_ctxStyleClipboard.color;if(_ctxStyleClipboard.size!==undefined)el.size=_ctxStyleClipboard.size;if(_ctxStyleClipboard.opacity!==undefined)el.opacity=_ctxStyleClipboard.opacity;if(_ctxStyleClipboard.rotation!==undefined)el.rotation=_ctxStyleClipboard.rotation;}});saveH();updateProps();Engine.reqRender();toast(lang==='ar'?'تم لصق النمط':'Style pasted');}
function bringForward(){if(!selIds.size)return;selIds.forEach(function(id){var idx=els.findIndex(function(e){return e.id===id;});if(idx>=0&&idx<els.length-1){var tmp=els[idx];els[idx]=els[idx+1];els[idx+1]=tmp;}});saveH();updateProps();updateLayers();Engine.reqRender();}
function sendBackward(){if(!selIds.size)return;var ids=Array.from(selIds);ids.reverse();ids.forEach(function(id){var idx=els.findIndex(function(e){return e.id===id;});if(idx>0){var tmp=els[idx];els[idx]=els[idx-1];els[idx-1]=tmp;}});saveH();updateProps();updateLayers();Engine.reqRender();}
function bringToFront(){if(!selIds.size)return;var moving=[];selIds.forEach(function(id){var idx=els.findIndex(function(e){return e.id===id;});if(idx>=0)moving.push(els.splice(idx,1)[0]);});moving.forEach(function(el){els.push(el);});saveH();updateProps();updateLayers();Engine.reqRender();}
function sendToBack(){if(!selIds.size)return;var moving=[];selIds.forEach(function(id){var idx=els.findIndex(function(e){return e.id===id;});if(idx>=0)moving.push(els.splice(idx,1)[0]);});moving.reverse().forEach(function(el){els.unshift(el);});saveH();updateProps();updateLayers();Engine.reqRender();}
function toggleLockSel(){if(!selIds.size)return;selIds.forEach(function(id){var el=els.find(function(e){return e.id===id;});if(el)el.locked=!el.locked;});saveH();updateProps();Engine.reqRender();}
