function drawTeamLogos(sx,sy,sw,sh){
if(teamLogos.A&&teamLogos.A.complete&&teamLogos.A.naturalWidth>0){
cx.save();cx.globalAlpha=teamLogoOpacity.A;
var lx2,ly2,lw2,lh2;
if(!pitchVertical){lx2=sx;ly2=sy;lw2=sw/2;lh2=sh;}
else{var p2=pRectLandscape();lx2=p2.x;ly2=p2.y;lw2=p2.w/2;lh2=p2.h;}
cx.drawImage(teamLogos.A,lx2+lw2*0.3,ly2+lh2*0.2,lw2*0.4,lh2*0.6);
cx.restore();}
if(teamLogos.B&&teamLogos.B.complete&&teamLogos.B.naturalWidth>0){
cx.save();cx.globalAlpha=teamLogoOpacity.B;
var lx3,ly3,lw3,lh3;
if(!pitchVertical){lx3=sx+sw/2;ly3=sy;lw3=sw/2;lh3=sh;}
else{var p2=pRectLandscape();lx3=p2.x+p2.w/2;ly3=p2.y;lw3=p2.w/2;lh3=p2.h;}
cx.drawImage(teamLogos.B,lx3+lw3*0.3,ly3+lh3*0.2,lw3*0.4,lh3*0.6);
cx.restore();}}
function loadTeamLogo(team,input){if(!input.files||!input.files[0])return;var file=input.files[0],reader=new FileReader();reader.onload=function(e){var img=new Image();img.onload=function(){teamLogos[team]=img;Engine.reqRender();rebuildSettingsModal();};img.src=e.target.result;};reader.readAsDataURL(file);}
